UPDATE notes
SET agent_reply = NULL,
    agent_reply_status = #{status},
    agent_reply_job_id = #{jobId}
WHERE id = #{id}

UPDATE notes
SET agent_reply_status = #{status},
    agent_reply_job_id = #{jobId}
WHERE id = #{id}

UPDATE notes
SET agent_reply = #{agentReply},
    agent_reply_status = 'done',
    agent_reply_job_id = #{jobId}
WHERE id = #{id}
